curl -s "http://export.arxiv.org/api/query?search_query=cat:cs.HC+AND+all:human+AI+collaboration&start=0&max_results=20&sortBy=submittedDate&sortOrder=descending" | python3 -c "
import sys, xml.etree.ElementTree as ET
ns = {'atom': 'http://www.w3.org/2005/Atom', 'arxiv': 'http://arxiv.org/schemas/atom'}
try:
    tree = ET.parse(sys.stdin)
    entries = tree.findall('atom:entry', ns)
    if not entries:
        print('No results')
    else:
        for entry in entries[:15]:
            title = entry.find('atom:title', ns).text.strip().replace('\n', ' ')[:120] if entry.find('atom:title', ns) is not None else 'N/A'
            arxiv_id = entry.find('atom:id', ns).text.split('/')[-1] if entry.find('atom:id', ns) is not None else 'N/A'
            published = entry.find('atom:published', ns).text[:10] if entry.find('atom:published', ns) is not None else 'N/A'
            authors = ', '.join([a.find('atom:name', ns).text for a in entry.findall('atom:author', ns)[:3]]) if entry.findall('atom:author', ns) else 'N/A'
            print(f'[{published}] {title} | {authors} | arXiv:{arxiv_id}')
except Exception as e:
    print(f'Error: {e}')
" 2>/dev/null

